import styled from 'styled-components';

export const FullPageImage = styled.div`
  width: 100vw;
  height: 100vh;
  position: absolute;
  top: 0;
  left: 0;
  background-color: #0B0000;
`;

export const Logo = styled.img`
  position: absolute;
  margin: auto;
`;
